import { MakeLogicType, actions, afterMount, kea, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { createFeaturePreviewSearch } from 'lib/utils/fuseSearch'
import { urls } from 'scenes/urls'

import { Breadcrumb, EarlyAccessFeatureType } from '~/types'


const search = createFeaturePreviewSearch<EarlyAccessFeatureType>()

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface earlyAccessFeaturesLogicValues {
    breadcrumbs: Breadcrumb[];
    earlyAccessFeatures: EarlyAccessFeatureType[];
    earlyAccessFeaturesLoading: boolean;
    filteredEarlyAccessFeatures: EarlyAccessFeatureType[];
    searchTerm: string;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface earlyAccessFeaturesLogicActions {
    loadEarlyAccessFeatures: () => any;
    loadEarlyAccessFeaturesFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadEarlyAccessFeaturesSuccess: (earlyAccessFeatures: EarlyAccessFeatureType[], payload?: any) => {
        earlyAccessFeatures: EarlyAccessFeatureType[];
        payload?: any;
    };
    setSearchTerm: (searchTerm: string) => {
        searchTerm: string;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface earlyAccessFeaturesLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        filteredEarlyAccessFeatures: (earlyAccessFeatures: EarlyAccessFeatureType[], searchTerm: string) => EarlyAccessFeatureType[];
    };
}

export type earlyAccessFeaturesLogicType = MakeLogicType<earlyAccessFeaturesLogicValues, earlyAccessFeaturesLogicActions, Record<string, any>, earlyAccessFeaturesLogicMeta>;

export const earlyAccessFeaturesLogic = kea<earlyAccessFeaturesLogicType>([
    path(['products', 'earlyAccessFeatures', 'frontend', 'earlyAccessFeaturesLogic']),

    actions({
        setSearchTerm: (searchTerm: string) => ({ searchTerm }),
    }),

    loaders({
        earlyAccessFeatures: {
            __default: [] as EarlyAccessFeatureType[],
            loadEarlyAccessFeatures: async () => {
                const response = await api.earlyAccessFeatures.list()
                return response.results
            },
        },
    }),

    reducers({
        searchTerm: [
            '',
            {
                setSearchTerm: (_, { searchTerm }) => searchTerm,
            },
        ],
    }),

    selectors({
        breadcrumbs: [
            () => [],
            (): Breadcrumb[] => [
                {
                    key: 'EarlyAccessFeatures',
                    name: 'Early access features',
                    path: urls.earlyAccessFeatures(),
                    iconType: 'early_access_feature',
                },
            ],
        ],

        filteredEarlyAccessFeatures: [
            (s) => [s.earlyAccessFeatures, s.searchTerm],
            (earlyAccessFeatures: EarlyAccessFeatureType[], searchTerm: string): EarlyAccessFeatureType[] => {
                return search(earlyAccessFeatures, searchTerm)
            },
        ],
    }),

    afterMount(({ actions }) => {
        actions.loadEarlyAccessFeatures()
    }),
])
